import React, { memo, useEffect, useMemo, useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
import { useInView } from "react-intersection-observer";
import { Clock, Users, Star, ShieldCheck } from "lucide-react";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const parseValue = (value) => {
  const numericPortion = parseFloat(value.replace(/[^0-9.,]/g, "").replace(",", "."));
  const decimals = value.includes(".") ? (value.split(".")[1]?.replace(/[^0-9]/g, "").length || 0) : 0;
  const suffix = value.replace(/[0-9.,]/g, "");
  return {
    targetValue: Number.isFinite(numericPortion) ? numericPortion : 0,
    suffix,
    decimals
  };
};

const useCountUpValue = (value, shouldAnimate) => {
  const reduceMotion = useReducedMotion();
  const { targetValue, suffix, decimals } = useMemo(() => parseValue(value), [value]);
  const [current, setCurrent] = useState(reduceMotion ? targetValue : 0);
  const [hasAnimated, setHasAnimated] = useState(false);

  useEffect(() => {
    if (reduceMotion) {
      setCurrent(targetValue);
      return;
    }

    if (!shouldAnimate || hasAnimated) return;

    setHasAnimated(true);
    let frame;
    const duration = 1400;
    const startTime = performance.now();

    const tick = (now) => {
      const progress = Math.min((now - startTime) / duration, 1);
      const nextValue = targetValue * progress;
      setCurrent(progress === 1 ? targetValue : nextValue);
      if (progress < 1) {
        frame = requestAnimationFrame(tick);
      }
    };

    frame = requestAnimationFrame(tick);

    return () => {
      if (frame) cancelAnimationFrame(frame);
    };
  }, [reduceMotion, shouldAnimate, targetValue, hasAnimated]);

  if (reduceMotion) {
    return `${value}`;
  }

  const formattedNumber =
    decimals > 0
      ? current.toFixed(decimals)
      : Math.round(current).toLocaleString("et-EE");

  return `${formattedNumber}${suffix}`;
};

const StatCard = ({ stat, index, inView }) => {
  const animatedValue = useCountUpValue(stat.value, inView);
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.5 }}
      animate={inView ? { opacity: 1, scale: 1 } : {}}
      transition={{
        duration: 0.5,
        delay: index * 0.1,
        type: "spring",
        stiffness: 100
      }}
      className="text-center group"
    >
      <div className="w-20 h-20 mx-auto mb-4 rounded-full bg-gradient-to-br from-[#0F62FE] to-[#0FB5AF] flex items-center justify-center text-white shadow-lg group-hover:shadow-xl group-hover:scale-110 transition-all duration-300 relative overflow-hidden">
        <stat.icon className="h-10 w-10 relative z-10" />
        <div className="absolute inset-0 bg-white/20 opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
      </div>
      <div className="text-4xl font-bold text-slate-900 dark:text-slate-100 mb-2 group-hover:text-[#0F62FE] dark:group-hover:text-[#0FB5AF] transition-colors duration-300">
        {animatedValue}
      </div>
      <div className="text-lg font-semibold text-slate-800 dark:text-slate-200 mb-1">
        {stat.label}
      </div>
      <div className="text-sm text-slate-600 dark:text-slate-400">
        {stat.description}
      </div>
    </motion.div>
  );
};

